exercises.solution_code:
#include <iostream>
#include <cstdlib>

template <typename T>
struct Coord
{
    T x;
    T y;
};

template <typename T>
using Point = Coord<T>;

using IntPoint = Point<int>;

int manhattan(const IntPoint& a, const IntPoint& b)
{
    return std::abs(a.x - b.x) + std::abs(a.y - b.y);
}

int main()
{
    int x1{}, y1{}, x2{}, y2{};
    std::cin >> x1 >> y1 >> x2 >> y2;

    IntPoint a { x1, y1 };
    IntPoint b { x2, y2 };

    std::cout << "A: (" << a.x << ", " << a.y << ")\n";
    std::cout << "B: (" << b.x << ", " << b.y << ")\n";
    std::cout << "Manhattan distance: " << manhattan(a, b) << '\n';

    return 0;
}
